/*
Theme Name: Team Haanpää
Author: WordPress Telex
Description: A modern, warm, and family-friendly Brazilian Jiu-jitsu theme for Team Haanpää. Light neutrals, navy and coral accents, editorial typography, and generous whitespace.
Version: 0.1.0
Requires at least: 6.4
Tested up to: 6.8
Requires PHP: 7.4
License: GPLv2 or later
Text Domain: team-haanpaa
Tags: block-theme, full-site-editing, one-column, custom-colors, custom-menu, editor-style
*/

/* ---------- Equal-height card grid ---------- */
.equal-cards > .wp-block-column {
  display: flex;
  flex-direction: column;
  flex-grow: 0;
}
.equal-cards > .wp-block-column > .wp-block-group {
  display: flex;
  flex-direction: column;
  flex-grow: 1;
}
.equal-cards .cta-bottom {
  margin-top: auto;
  justify-content: center;
}

/* ---------- Footer margin reset ---------- */
.wp-site-blocks > footer {
  margin-block-start: 0;
}

/* ---------- Nav link underline animation ---------- */
.header-nav a {
  position: relative;
  text-decoration: none;
}
.header-nav a::after {
  content: '';
  position: absolute;
  bottom: -4px;
  left: 0;
  width: 100%;
  height: 1px;
  background-color: var(--wp--preset--color--coral);
  transform: scaleX(0);
  transform-origin: right;
  transition: transform 0.3s ease;
}
.header-nav a:hover::after {
  transform: scaleX(1);
  transform-origin: left;
}

/* ---------- Frosted header ---------- */
.site-header {
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  border-bottom: 1px solid rgba(226, 221, 215, 0.5);
}

/* ---------- Hero overlay gradient ---------- */
.hero-cover .wp-block-cover__background {
  background: linear-gradient(
    180deg,
    rgba(26, 43, 74, 0.3) 0%,
    rgba(200, 150, 80, 0.25) 50%,
    rgba(26, 43, 74, 0.6) 100%
  ) !important;
}

/* ---------- Pill button ---------- */
.btn-pill .wp-block-button__link {
  border-radius: 999px !important;
  border: 1px solid rgba(255, 255, 255, 0.1);
  transition: all 200ms ease;
}
.btn-pill .wp-block-button__link:hover {
  transform: translateY(-2px);
  box-shadow: 0 8px 24px rgba(26, 43, 74, 0.6);
  border-color: rgba(255, 255, 255, 0.2);
}

/* ---------- Coral CTA button hover ---------- */
.btn-coral .wp-block-button__link {
  transition: all 200ms ease;
}
.btn-coral .wp-block-button__link:hover {
  transform: scale(1.03);
  box-shadow: 0 4px 16px rgba(232, 97, 58, 0.35);
}

/* ---------- Value card subtle lift ---------- */
.value-card {
  transition: transform 0.25s ease, box-shadow 0.25s ease;
}
.value-card:hover {
  transform: translateY(-4px);
  box-shadow: 0 12px 32px rgba(26, 43, 74, 0.08);
}

/* ---------- Instructor image treatment ---------- */
.instructor-img img {
  border-radius: 8px;
  object-fit: cover;
}

/* ---------- Schedule table styling ---------- */
.schedule-table table {
  border-collapse: collapse;
  width: 100%;
}
.schedule-table th,
.schedule-table td {
  padding: 1rem 1.25rem;
  text-align: left;
  border-bottom: 1px solid var(--wp--preset--color--warm-gray);
}
.schedule-table th {
  text-transform: uppercase;
  letter-spacing: 0.1em;
  font-size: 0.8rem;
  color: var(--wp--preset--color--coral);
}
.schedule-table tr:last-child td {
  border-bottom: none;
}

/* ---------- Scroll margin for anchor targets ---------- */
[id] {
  scroll-margin-top: 100px;
}

/* ---------- Fade-in animation ---------- */
@keyframes fadeInUp {
  from {
    opacity: 0;
    transform: translateY(24px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}
.fade-in-up {
  animation: fadeInUp 0.7s ease both;
}

{
  "$schema": "https://schemas.wp.org/trunk/theme.json",
  "version": 3,
  "settings": {
    "appearanceTools": true,
    "layout": {
      "contentSize": "860px",
      "wideSize": "1280px"
    },
    "color": {
      "palette": [
        { "slug": "offwhite", "color": "#FAF8F4", "name": "Off-white" },
        { "slug": "navy", "color": "#1A2B4A", "name": "Navy" },
        { "slug": "coral", "color": "#E8613A", "name": "Coral" },
        { "slug": "warm-gray", "color": "#E2DDD7", "name": "Warm Gray" },
        { "slug": "white", "color": "#FFFFFF", "name": "White" },
        { "slug": "light-coral", "color": "#FFF0EB", "name": "Light Coral" },
        { "slug": "dark-navy", "color": "#111E36", "name": "Dark Navy" }
      ]
    },
    "typography": {
      "fontFamilies": [
        {
          "fontFamily": "'Playfair Display', Georgia, serif",
          "slug": "playfair",
          "name": "Playfair Display"
        },
        {
          "fontFamily": "'DM Sans', 'Helvetica Neue', Arial, sans-serif",
          "slug": "dm-sans",
          "name": "DM Sans"
        }
      ],
      "fontSizes": [
        { "slug": "small", "size": "0.875rem", "name": "Small" },
        { "slug": "medium", "size": "1rem", "name": "Medium" },
        { "slug": "large", "size": "1.25rem", "name": "Large" },
        { "slug": "x-large", "size": "1.75rem", "name": "Extra Large" },
        { "slug": "xx-large", "size": "2.25rem", "name": "2X Large" },
        { "slug": "huge", "size": "clamp(2.5rem, 4vw, 3.5rem)", "name": "Huge" }
      ]
    },
    "spacing": {
      "units": ["px", "em", "rem", "vh", "vw", "%"],
      "spacingSizes": [
        { "slug": "10", "size": "0.5rem", "name": "1" },
        { "slug": "20", "size": "1rem", "name": "2" },
        { "slug": "30", "size": "1.5rem", "name": "3" },
        { "slug": "40", "size": "2rem", "name": "4" },
        { "slug": "50", "size": "3rem", "name": "5" },
        { "slug": "60", "size": "4rem", "name": "6" },
        { "slug": "70", "size": "5rem", "name": "7" },
        { "slug": "80", "size": "7rem", "name": "8" }
      ]
    }
  },
  "styles": {
    "color": {
      "background": "#FAF8F4",
      "text": "#1A2B4A"
    },
    "typography": {
      "fontFamily": "'DM Sans', 'Helvetica Neue', Arial, sans-serif",
      "fontSize": "1rem",
      "lineHeight": "1.6"
    },
    "elements": {
      "heading": {
        "typography": {
          "fontFamily": "'Playfair Display', Georgia, serif",
          "fontWeight": "900",
          "lineHeight": "1.15"
        },
        "color": {
          "text": "#1A2B4A"
        }
      },
      "link": {
        "color": {
          "text": "#E8613A"
        },
        ":hover": {
          "color": {
            "text": "#1A2B4A"
          }
        }
      },
      "button": {
        "typography": {
          "fontSize": "0.875rem",
          "fontWeight": "500",
          "letterSpacing": "0.1em",
          "textTransform": "uppercase"
        },
        "color": {
          "background": "#E8613A",
          "text": "#FFFFFF"
        },
        "border": {
          "radius": "4px"
        },
        ":hover": {
          "color": {
            "background": "#d14e2a",
            "text": "#FFFFFF"
          }
        }
      }
    },
    "blocks": {
      "core/navigation": {
        "typography": {
          "fontSize": "0.8125rem",
          "fontWeight": "500",
          "letterSpacing": "0.15em",
          "textTransform": "uppercase"
        },
        "color": {
          "text": "#1A2B4A"
        }
      },
      "core/site-title": {
        "typography": {
          "fontFamily": "'Playfair Display', Georgia, serif",
          "fontWeight": "900",
          "fontSize": "1.5rem",
          "letterSpacing": "-0.02em"
        },
        "color": {
          "text": "#1A2B4A"
        },
        "elements": {
          "link": {
            "color": {
              "text": "#1A2B4A"
            },
            ":hover": {
              "color": {
                "text": "#E8613A"
              }
            }
          }
        }
      }
    }
  },
  "templateParts": [
    { "name": "header", "title": "Header", "area": "header" },
    { "name": "footer", "title": "Footer", "area": "footer" }
  ]
}

/**
 * Theme Assets Editor Rewrite
 *
 * This script rewrites URLs in block attributes that start with 'theme:./'
 * to point to the correct theme assets.
 * It allows blocks in templates to reference theme assets using relative paths in the editor.
**/
(function (wp) {
	const base = window.THEME_ASSETS_BASE_URL || '';
	const prefix = 'theme:./';

	if (!wp?.hooks || !wp?.compose) return;

	const rewrite = (url) => {
		if (typeof url === 'string' && url.startsWith(prefix)) {
			const path = url.slice(prefix.length);
			return base + '/' + path;
		}
		return null;
	};

	// Recursively walk any value and rewrite all theme:./ URLs found in it.
	// Returns a new structure if anything changed, or null if nothing changed.
	const deepRewrite = (value) => {
		if (typeof value === 'string') {
			return rewrite(value);
		}
		if (Array.isArray(value)) {
			let changed = false;
			const result = value.map((item) => {
				const rewritten = deepRewrite(item);
				if (rewritten !== null) {
					changed = true;
					return rewritten;
				}
				return item;
			});
			return changed ? result : null;
		}
		if (value && typeof value === 'object') {
			let changed = false;
			const result = {};
			for (const key of Object.keys(value)) {
				const rewritten = deepRewrite(value[key]);
				if (rewritten !== null) {
					changed = true;
					result[key] = rewritten;
				} else {
					result[key] = value[key];
				}
			}
			return changed ? result : null;
		}
		return null;
	};

	wp.hooks.addFilter(
		'editor.BlockEdit',
		'theme-assets/rewrite-image-urls',
		wp.compose.createHigherOrderComponent((BlockEdit) => (props) => {
			const { attributes } = props;

			// Deep-rewrite all attributes to resolve any theme:./ URLs
			const rewrittenAttributes = deepRewrite(attributes);

			// Pass rewritten URLs to BlockEdit for display only, without persisting changes
			if (rewrittenAttributes) {
				const modifiedProps = {
					...props,
					attributes: rewrittenAttributes,
				};
				return wp.element.createElement(BlockEdit, modifiedProps);
			}

			return wp.element.createElement(BlockEdit, props);
		}, 'withThemeAssetsRewrite')
	);

})(window.wp);
